        r'^\s*SELECT\s+(?P<select>.+?)\s*'
        r'(?:FROM\s+(?P<from>.+?)\s*)?'
        r'(?:WHERE\s+(?P<where>.+?)\s*)?'
        r'(?:ORDER\s+BY\s+(?P<order_by>.+?)\s*)?$',
        query,
        flags=re.IGNORECASE | re.DOTALL
    )
    if not m:
        raise ValueError("Invalid query. Expected syntax: SELECT <columns> [FROM <...>] [WHERE <...>] [ORDER BY <...>]")

    select_part = (m.group('select') or '').strip()
    where_part = (m.group('where') or '').strip()
    order_part = (m.group('order_by') or '').strip()
    from_part = (m.group('from') or '').strip()

    select_list = _parse_select_list(select_part)

    # Build predicate
    if where_part:
        tokens = _tokenize_where(where_part)
        parser = _Parser(tokens)
        predicate = parser.parse()
    else:
        predicate = lambda _rec: True

    # Build order specs
    order_specs = _parse_order_by(order_part) if order_part else []

    return QueryPlan(
        select_list=select_list,
        order_specs=order_specs,
        predicate=predicate,
        where_expr=where_part if where_part else None,
        from_source=from_part if from_part else None,
        raw_sql=query,
    )


def _format_select_for_log(select_list: List[Tuple[str, str]]) -> str:
    if len(select_list) == 1 and select_list[0] == ('*', '*'):
        return "*"
    parts: List[str] = []
    for src, alias in select_list:
        default_alias = src.split('.')[-1]
        if alias != default_alias:
            parts.append(f"{src} AS {alias}")
        else:
            parts.append(src)
    return ", ".join(parts)


def _format_order_for_log(order_specs: List[Tuple[str, bool]]) -> str:
    if not order_specs:
        return "None"
    parts = []
    for field, asc in order_specs:
        parts.append(f"{field} {'ASC' if asc else 'DESC'}")
    return ", ".join(parts)


def execute_query(records: List[Dict[str, Any]], plan: QueryPlan) -> List[Dict[str, Any]]:
    """
    Pure function: execute a parsed query plan against the given records.
    Does not mutate input records. Raises ValueError on invalid input.
    """
    if not isinstance(records, list) or not all(isinstance(r, dict) for r in records):
        raise ValueError("records must be a list of dictionaries")

    logger = logging.getLogger("sql_query")

    logger.info("Executing query over %d record(s)...", len(records))

    # Filter
    filtered = [rec for rec in records if plan.predicate(rec)]
    logger.info("After WHERE filter: %d record(s) match.", len(filtered))

    # Order
    if plan.order_specs:
        logger.info("Applying ORDER BY: %s", _format_order_for_log(plan.order_specs))
        filtered = _sort_records(filtered, plan.order_specs)

    # Projection
    result: List[Dict[str, Any]] = []
    if len(plan.select_list) == 1 and plan.select_list[0] == ('*', '*'):
        for rec in filtered:
            result.append(dict(rec))
    else:
        for rec in filtered:
            out: Dict[str, Any] = {}
            for src, alias in plan.select_list:
                out[alias] = _get_value(src, rec)
            result.append(out)

    return result


def handle_sql_query(records: List[Dict[str, Any]], sql_command: str) -> List[Dict[str, Any]]:
    """
    Execute a simple SQL-like query over a list of dictionaries.

    Supported syntax (case-insensitive keywords):
      SELECT <columns> [FROM <ignored>] [WHERE <expression>] [ORDER BY <field> [ASC|DESC], ...]
    - <columns>: '*' or comma-separated list of identifiers with optional 'AS alias'
    - WHERE: supports comparisons with =, !=, <, <=, >, >=, LIKE; logical AND, OR, NOT; parentheses; TRUE/FALSE/NULL literals
    - ORDER BY: one or more fields with optional ASC/DESC

    Returns list of dictionaries representing the result set.

    Raises ValueError on parse or execution errors.
    """
    # Initialize logging within this function
    logger = logging.getLogger("sql_query")
    if not logger.handlers:
        handler = logging.StreamHandler()
        handler.setFormatter(logging.Formatter("%(asctime)s - %(levelname)s - %(message)s"))
        logger.addHandler(handler)
        logger.setLevel(logging.INFO)
        logger.propagate = False

    try:
        logger.info("SQL query received:\n%s", sql_command.strip())
        plan = parse_sql_query(sql_command)

        # Log operations parsed from the query
        logger.info("Parsed operations:")
        logger.info("  FROM: %s", plan.from_source or "None")
        logger.info("  SELECT: %s", _format_select_for_log(plan.select_list))
        logger.info("  WHERE: %s", plan.where_expr or "None")
        logger.info("  ORDER BY: %s", _format_order_for_log(plan.order_specs))

        result = execute_query(records, plan)

        logger.info("Query result: %d row(s).", len(result))
        logger.info("Result rows:\n%s", pformat(result, width=100))

        return result
    except ValueError as e:
        logger.error("Query failed: %s", e)
        raise
    except Exception as e:
        logger.exception("Failed to execute query: %s", e)
        raise ValueError(f"Failed to execute query: {e}")
